using Microsoft.EntityFrameworkCore;
class ProductContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Product>(entity =>
        {
            entity.ToContainer("Products");

            // EF Core 9 renamed the default discriminator property from "Discriminator" to "$type".
            // Existing 500K documents use "Discriminator", and direct SQL queries reference c.Discriminator.
            entity.HasDiscriminator<string>("Discriminator");

            // EF Core 9 changed id format from "Product|123" to just "123".
            // Existing documents use the compound format; this preserves compatibility.
            entity.HasRootDiscriminatorInJsonId(true);
        });
        // HasIndex removed — EF Core 9 Cosmos provider throws at startup.
        // Manage indexing via the Azure Portal or Bicep/Terraform indexing policy.
    }
}
class Product { public int Id { get; set; } public string Sku { get; set; } }

