using Microsoft.EntityFrameworkCore;

class CosmosQuery
{
    // EF Core 9 Cosmos provider no longer supports synchronous I/O — use async.
    async Task FindProducts(ProductContext ctx)
    {
        // Direct Cosmos SQL — safe because we explicitly kept "Discriminator" as the
        // discriminator property name (see ProductContext). Without that config, EF Core 9
        // would write "$type" and this query would silently return zero results.
        var sql = "SELECT * FROM c WHERE c.Discriminator = 'Product' AND c.Sku = @sku";

        // ToList() throws in EF Core 9 Cosmos; use ToListAsync().
        var products = await ctx.Products.Where(p => p.Sku == "ABC").ToListAsync();
    }
}

